//! Release & channel storage (Tower 2).
//!
//! L2 **component releases** (one entity's versioned parts), L1 **vehicle
//! releases** (a tagged combination of component releases — the desired
//! whole-vehicle state), and **channel** pointers. Resolving a channel yields
//! the desired [`wire::Tree`]; the per-vehicle *campaign* to reach it is
//! generated by [`wire::flash_plan`], not stored here.
//!
//! Releases are **content-identified**: a component's identity is the hash of
//! its parts, a vehicle's identity is the hash of its member set. Creating a
//! release is therefore idempotent — the same content reuses the existing
//! release (whatever its version), so a reconcile only cuts a new version when
//! the content actually changed. The `version` is just a human label (a build
//! number); `created_at` is the build time (when this content was first cut).

use axum::extract::{Path, Query, State};
use axum::Json;
use serde::{Deserialize, Serialize};
use sqlx::postgres::PgRow;
use sqlx::{PgPool, Row};
use wire::{ArtifactRef, ContentHash, Entity, Part, Tree};

use crate::content::{AppError, AppState};

// --- request / response bodies ---------------------------------------------

/// `POST /admin/component-releases` body — one entity's versioned parts.
#[derive(Deserialize)]
pub struct NewComponentRelease {
    pub entity_path: String,
    pub entity_kind: String,
    pub version: String,
    pub parts: Vec<NewPart>,
}

#[derive(Deserialize)]
pub struct NewPart {
    pub id: String,
    pub kind: String,
    pub content: ContentHash,
}

/// `POST /admin/vehicle-releases` body — a tagged combination of component
/// releases (the desired whole-vehicle state).
#[derive(Deserialize)]
pub struct NewVehicleRelease {
    pub tag: String,
    pub version: String,
    pub members: Vec<i64>,
}

/// `PUT /admin/channel-targets` body — point a (channel, target_type, profile)
/// at a vehicle (target) release.
#[derive(Deserialize)]
pub struct SetChannelTarget {
    pub channel: String,
    pub target_type: String,
    pub profile: String,
    pub vehicle_release_id: i64,
}

/// Query for resolving a channel target. `target_type` / `profile` are optional —
/// omit them to resolve a channel that has a single target (the common case);
/// supply both to disambiguate when a channel serves several.
#[derive(Deserialize)]
pub struct TargetSelector {
    pub channel: String,
    pub target_type: Option<String>,
    pub profile: Option<String>,
}

/// A resolved release. `reused` is true when the content already had a release
/// (so the proposed version was ignored and the existing one returned).
#[derive(Serialize)]
pub struct ReleaseRef {
    pub id: i64,
    pub version: String,
    pub created_at: String,
    pub reused: bool,
}

impl ReleaseRef {
    fn from_row(row: &PgRow, reused: bool) -> Self {
        ReleaseRef {
            id: row.get("id"),
            version: row.get("version"),
            created_at: row.get("created_at"),
            reused,
        }
    }
}

/// `GET /admin/channel-targets` response — the resolved target's current vehicle
/// release (the build-number source for a reconcile) + its tree hash, or a null
/// `vehicle` if the target is unset/unknown.
#[derive(Serialize)]
pub struct ChannelTargetState {
    pub channel: String,
    pub vehicle: Option<VehicleRef>,
    pub tree_hash: Option<String>,
}

/// `PUT /admin/channel-targets` response — the resolved tuple + the tree hash
/// that binds plan -> execute.
#[derive(Serialize)]
pub struct ChannelTargetRef {
    pub channel: String,
    pub target_type: String,
    pub profile: String,
    pub vehicle_release_id: i64,
    pub tree_hash: String,
}

#[derive(Serialize)]
pub struct VehicleRef {
    pub id: i64,
    pub tag: String,
    pub version: String,
    pub created_at: String,
}

// --- handlers --------------------------------------------------------------

/// `POST /admin/component-releases` — mint an L2 component release, idempotent on
/// content. Same parts as an existing release for this entity → that release is
/// returned (`reused`); otherwise a new one is cut with the proposed `version`.
pub async fn create_component_release(
    State(s): State<AppState>,
    Json(req): Json<NewComponentRelease>,
) -> Result<Json<ReleaseRef>, AppError> {
    let pool = s.pool()?;
    let identity = component_identity(&req.entity_kind, &req.parts);

    if let Some(row) = sqlx::query(
        "SELECT id, version, created_at::text AS created_at FROM component_releases \
         WHERE entity_path = $1 AND identity_hash = $2",
    )
    .bind(&req.entity_path)
    .bind(&identity)
    .fetch_optional(pool)
    .await
    .map_err(db)?
    {
        return Ok(Json(ReleaseRef::from_row(&row, true)));
    }

    let row = sqlx::query(
        "INSERT INTO component_releases (entity_path, entity_kind, version, identity_hash) \
         VALUES ($1, $2, $3, $4) RETURNING id, version, created_at::text AS created_at",
    )
    .bind(&req.entity_path)
    .bind(&req.entity_kind)
    .bind(&req.version)
    .bind(&identity)
    .fetch_one(pool)
    .await
    .map_err(db)?;
    let id: i64 = row.get("id");

    for p in &req.parts {
        sqlx::query(
            "INSERT INTO component_release_parts (release_id, part_id, part_kind, content_hash) \
             VALUES ($1, $2, $3, $4)",
        )
        .bind(id)
        .bind(&p.id)
        .bind(&p.kind)
        .bind(p.content.to_prefixed())
        .execute(pool)
        .await
        .map_err(db)?;
    }
    Ok(Json(ReleaseRef::from_row(&row, false)))
}

/// `POST /admin/vehicle-releases` — mint an L1 vehicle release (the desired
/// whole-vehicle state), idempotent on content. Same member set for this tag →
/// that release is returned (`reused`); otherwise a new one is cut.
pub async fn create_vehicle_release(
    State(s): State<AppState>,
    Json(req): Json<NewVehicleRelease>,
) -> Result<Json<ReleaseRef>, AppError> {
    let pool = s.pool()?;
    let identity = vehicle_identity(&req.members);

    if let Some(row) = sqlx::query(
        "SELECT id, version, created_at::text AS created_at FROM vehicle_releases \
         WHERE tag = $1 AND identity_hash = $2",
    )
    .bind(&req.tag)
    .bind(&identity)
    .fetch_optional(pool)
    .await
    .map_err(db)?
    {
        return Ok(Json(ReleaseRef::from_row(&row, true)));
    }

    let row = sqlx::query(
        "INSERT INTO vehicle_releases (tag, version, identity_hash) \
         VALUES ($1, $2, $3) RETURNING id, version, created_at::text AS created_at",
    )
    .bind(&req.tag)
    .bind(&req.version)
    .bind(&identity)
    .fetch_one(pool)
    .await
    .map_err(db)?;
    let id: i64 = row.get("id");

    for m in &req.members {
        sqlx::query(
            "INSERT INTO vehicle_release_members (vehicle_release_id, component_release_id) \
             VALUES ($1, $2)",
        )
        .bind(id)
        .bind(m)
        .execute(pool)
        .await
        .map_err(db)?;
    }
    Ok(Json(ReleaseRef::from_row(&row, false)))
}

/// `PUT /admin/channel-targets` — point (channel, target_type, profile) at a
/// vehicle release, and store the `tree_hash` of its resolved tree.
pub async fn set_channel_target(
    State(s): State<AppState>,
    Json(req): Json<SetChannelTarget>,
) -> Result<Json<ChannelTargetRef>, AppError> {
    let pool = s.pool()?;
    let tree = resolve_members_to_tree(pool, req.vehicle_release_id)
        .await
        .map_err(db)?;
    let th = tree_hash(&tree);
    sqlx::query(
        "INSERT INTO channel_targets \
           (channel, target_type, profile, vehicle_release_id, tree_hash, updated_at) \
         VALUES ($1, $2, $3, $4, $5, now()) \
         ON CONFLICT (channel, target_type, profile) \
           DO UPDATE SET vehicle_release_id = $4, tree_hash = $5, updated_at = now()",
    )
    .bind(&req.channel)
    .bind(&req.target_type)
    .bind(&req.profile)
    .bind(req.vehicle_release_id)
    .bind(&th)
    .execute(pool)
    .await
    .map_err(db)?;
    Ok(Json(ChannelTargetRef {
        channel: req.channel,
        target_type: req.target_type,
        profile: req.profile,
        vehicle_release_id: req.vehicle_release_id,
        tree_hash: th,
    }))
}

/// `GET /admin/channel-targets?channel=&target_type=&profile=` — the resolved
/// target's current vehicle release (the build-number source for a reconcile) +
/// its tree hash. `target_type`/`profile` are optional (default: the channel's
/// single target). A null `vehicle` means the target is unset/unknown.
pub async fn get_channel_target(
    State(s): State<AppState>,
    Query(sel): Query<TargetSelector>,
) -> Result<Json<ChannelTargetState>, AppError> {
    let pool = s.pool()?;
    let row = sqlx::query(
        "SELECT v.id, v.tag, v.version, v.created_at::text AS created_at, ct.tree_hash \
         FROM channel_targets ct JOIN vehicle_releases v ON v.id = ct.vehicle_release_id \
         WHERE ct.channel = $1 \
           AND ($2::text IS NULL OR ct.target_type = $2) \
           AND ($3::text IS NULL OR ct.profile = $3) \
         ORDER BY ct.updated_at DESC LIMIT 1",
    )
    .bind(&sel.channel)
    .bind(&sel.target_type)
    .bind(&sel.profile)
    .fetch_optional(pool)
    .await
    .map_err(db)?;

    let (vehicle, tree_hash) = match row {
        Some(r) => (
            Some(VehicleRef {
                id: r.get("id"),
                tag: r.get("tag"),
                version: r.get("version"),
                created_at: r.get("created_at"),
            }),
            Some(r.get::<String, _>("tree_hash")),
        ),
        None => (None, None),
    };
    Ok(Json(ChannelTargetState {
        channel: sel.channel,
        vehicle,
        tree_hash,
    }))
}

/// `GET /channel-targets/tree?channel=&target_type=&profile=` — resolve a target
/// to its desired tree. `target_type`/`profile` optional (default: the channel's
/// single target).
pub async fn channel_target_tree(
    State(s): State<AppState>,
    Query(sel): Query<TargetSelector>,
) -> Result<Json<Tree>, AppError> {
    let tree = resolve_channel_target(
        s.pool()?,
        &sel.channel,
        sel.target_type.as_deref(),
        sel.profile.as_deref(),
    )
    .await
    .map_err(db)?
    .ok_or(AppError::NotFound)?;
    Ok(Json(tree))
}

/// `GET /admin/artifacts/{inner}` — does Tower 2 already have this content?
/// `200` + the ref if stored, `404` if not — so a build step can skip the upload.
pub async fn artifact_exists(
    State(s): State<AppState>,
    Path(inner): Path<String>,
) -> Result<Json<ArtifactRef>, AppError> {
    let inner: ContentHash = inner.parse().map_err(|_| AppError::BadHash)?;
    match s.index.get(&inner).await? {
        Some(e) => Ok(Json(ArtifactRef {
            inner: e.inner,
            outer: e.outer,
            size: e.size,
        })),
        None => Err(AppError::NotFound),
    }
}

// --- identity --------------------------------------------------------------

/// A component release's content identity: a hash over its entity kind and its
/// parts (sorted by id, so order doesn't matter). Two releases with the same
/// identity have byte-identical content.
fn component_identity(entity_kind: &str, parts: &[NewPart]) -> String {
    let mut sorted: Vec<&NewPart> = parts.iter().collect();
    sorted.sort_by(|a, b| a.id.cmp(&b.id));

    let mut buf = String::new();
    buf.push_str(entity_kind);
    buf.push('\n');
    for p in sorted {
        buf.push_str(&p.id);
        buf.push('\0');
        buf.push_str(&p.kind);
        buf.push('\0');
        buf.push_str(&p.content.to_prefixed());
        buf.push('\n');
    }
    ContentHash::of(buf.as_bytes()).to_prefixed()
}

/// A vehicle release's content identity: a hash over its (sorted, deduped)
/// member component-release ids. Member ids are themselves content-deduped, so
/// the same whole-vehicle content yields the same identity.
fn vehicle_identity(members: &[i64]) -> String {
    let mut sorted = members.to_vec();
    sorted.sort_unstable();
    sorted.dedup();
    let joined = sorted
        .iter()
        .map(|m| m.to_string())
        .collect::<Vec<_>>()
        .join(",");
    ContentHash::of(joined.as_bytes()).to_prefixed()
}

// --- resolution ------------------------------------------------------------

/// Resolve a (channel, target_type?, profile?) to its desired [`wire::Tree`].
/// `None` when the target is unknown (or, without an explicit type/profile, the
/// channel has zero or several targets — the caller then asks for a selector).
async fn resolve_channel_target(
    pool: &PgPool,
    channel: &str,
    target_type: Option<&str>,
    profile: Option<&str>,
) -> sqlx::Result<Option<Tree>> {
    let Some(vehicle_id) = channel_target_vehicle(pool, channel, target_type, profile).await?
    else {
        return Ok(None);
    };
    Ok(Some(resolve_members_to_tree(pool, vehicle_id).await?))
}

/// The vehicle release id a (channel, target_type?, profile?) points at. With an
/// explicit type+profile it's an exact lookup; without, it resolves a channel
/// that has exactly one target (zero or many -> `None`).
async fn channel_target_vehicle(
    pool: &PgPool,
    channel: &str,
    target_type: Option<&str>,
    profile: Option<&str>,
) -> sqlx::Result<Option<i64>> {
    if let (Some(t), Some(p)) = (target_type, profile) {
        let row = sqlx::query(
            "SELECT vehicle_release_id FROM channel_targets \
             WHERE channel = $1 AND target_type = $2 AND profile = $3",
        )
        .bind(channel)
        .bind(t)
        .bind(p)
        .fetch_optional(pool)
        .await?;
        return Ok(row.map(|r| r.get("vehicle_release_id")));
    }
    let rows = sqlx::query("SELECT vehicle_release_id FROM channel_targets WHERE channel = $1")
        .bind(channel)
        .fetch_all(pool)
        .await?;
    Ok(if rows.len() == 1 {
        Some(rows[0].get("vehicle_release_id"))
    } else {
        None
    })
}

/// A vehicle release id -> its desired [`wire::Tree`] (member component releases
/// -> their entities + parts).
async fn resolve_members_to_tree(pool: &PgPool, vehicle_id: i64) -> sqlx::Result<Tree> {
    let members = sqlx::query(
        "SELECT component_release_id FROM vehicle_release_members WHERE vehicle_release_id = $1",
    )
    .bind(vehicle_id)
    .fetch_all(pool)
    .await?;

    let mut tree = Tree::default();
    for m in members {
        let rid: i64 = m.get("component_release_id");
        let row = sqlx::query(
            "SELECT entity_path, entity_kind, version FROM component_releases WHERE id = $1",
        )
        .bind(rid)
        .fetch_one(pool)
        .await?;
        let path: String = row.get("entity_path");
        let mut entity = Entity {
            kind: row.get("entity_kind"),
            version: Some(row.get("version")),
            update_mode: None,
            parts: Vec::new(),
        };
        let parts =
            sqlx::query("SELECT part_id, part_kind, content_hash FROM component_release_parts WHERE release_id = $1")
                .bind(rid)
                .fetch_all(pool)
                .await?;
        for p in parts {
            let content: String = p.get("content_hash");
            let Ok(content) = content.parse::<ContentHash>() else {
                continue;
            };
            entity.parts.push(Part {
                kind: p.get("part_kind"),
                id: p.get("part_id"),
                content,
            });
        }
        tree.entities.insert(path, entity);
    }
    Ok(tree)
}

/// Content-stable canonical hash of a resolved tree: entity paths in order (the
/// [`Tree`] map is already sorted), each with its parts sorted by id. Binds
/// plan -> execute (multi-profile spec §2.2) — unlike a vehicle release's
/// id-based identity hash, it is identical across DB instances for the same
/// content.
fn tree_hash(tree: &Tree) -> String {
    let mut buf = String::new();
    for (path, entity) in &tree.entities {
        buf.push_str(path);
        buf.push('\n');
        let mut parts: Vec<&Part> = entity.parts.iter().collect();
        parts.sort_by(|a, b| a.id.cmp(&b.id));
        for p in parts {
            buf.push_str(&p.id);
            buf.push('\0');
            buf.push_str(&p.content.to_prefixed());
            buf.push('\n');
        }
    }
    ContentHash::of(buf.as_bytes()).to_prefixed()
}

/// Map a database error into an `AppError`.
fn db(e: sqlx::Error) -> AppError {
    AppError::Internal(e.into())
}

#[cfg(test)]
mod tests {
    use super::*;

    fn part(id: &str, kind: &str, content: &str) -> NewPart {
        NewPart {
            id: id.into(),
            kind: kind.into(),
            content: ContentHash::of(content.as_bytes()),
        }
    }

    #[test]
    fn component_identity_ignores_part_order() {
        let a = vec![part("kernel", "bank", "k"), part("rootfs", "bank", "r")];
        let b = vec![part("rootfs", "bank", "r"), part("kernel", "bank", "k")];
        assert_eq!(
            component_identity("bank", &a),
            component_identity("bank", &b)
        );
    }

    #[test]
    fn component_identity_tracks_content_kind_and_partset() {
        let base = vec![part("kernel", "bank", "k1")];
        // content change
        assert_ne!(
            component_identity("bank", &base),
            component_identity("bank", &[part("kernel", "bank", "k2")])
        );
        // added part
        assert_ne!(
            component_identity("bank", &base),
            component_identity(
                "bank",
                &[part("kernel", "bank", "k1"), part("rootfs", "bank", "r")]
            )
        );
        // entity kind change
        assert_ne!(
            component_identity("bank", &base),
            component_identity("rt", &base)
        );
    }

    #[test]
    fn vehicle_identity_ignores_order_and_dupes() {
        assert_eq!(vehicle_identity(&[1, 2, 3]), vehicle_identity(&[3, 2, 1]));
        assert_eq!(
            vehicle_identity(&[1, 2, 2, 3]),
            vehicle_identity(&[1, 2, 3])
        );
        assert_ne!(vehicle_identity(&[1, 2]), vehicle_identity(&[1, 2, 3]));
    }
}
